using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create sketch
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr sketch = sketches->add(rootComp->xYConstructionPlane());
    if (!sketch)
        return false;

    // Create sketch circle
    Ptr curves = sketch->sketchCurves();
    if (!curves)
        return false;

    Ptr circles = curves->sketchCircles();
    if (!circles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    circles->addByCenterRadius(centerPoint, 5.0);

    // Get the profile defined by the circle
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);

    // Create an extrusion input
    Ptr features = rootComp->features();
    if (!features)
        return false;

    Ptr extrudes = features->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5.0);

    // Set the distance extent to be symmetric
    extInput->setDistanceExtent(true, distance);

    // Set the extrude to be a solid one
    extInput->isSolid(true);

    // Create an cylinder
    Ptr extrude = extrudes->add(extInput);
    if (!extrude)
        return false;

    // Create sketch line
    Ptr sketchLines = curves->sketchLines();
    if (!sketchLines)
        return false;
    Ptr startPoint = Point3D::create(5.0, 5.0, 0);
    Ptr endPoint = Point3D::create(5.0, 10.0, 0);
    Ptr sketchLineOne = sketchLines->addByTwoPoints(startPoint, endPoint);
    Ptr endPointTwo = Point3D::create(10.0, 5.0, 0);
    Ptr sketchLineTwo = sketchLines->addByTwoPoints(startPoint, endPointTwo);

    // Create three sketch points
    Ptr sketchPoints = sketch->sketchPoints();
    if (!sketchPoints)
        return false;
    Ptr positionOne = Point3D::create(0, 5.0, 0);
    Ptr sketchPointOne = sketchPoints->add(positionOne);
    Ptr positionTwo = Point3D::create(5.0, 0, 0);
    Ptr sketchPointTwo = sketchPoints->add(positionTwo);
    Ptr positionThree = Point3D::create(0, -5.0, 0);
    Ptr sketchPointThree = sketchPoints->add(positionThree);

    prof = profs->item(0);

    // Get construction planes
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;

    // Create construction plane input
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;

    // Add construction plane by offset
    Ptr offsetValue = ValueInput::createByReal(3.0);
    planeInput->setByOffset(prof, offsetValue);
    Ptr planeOne = planes->add(planeInput);

    // Get the health state of a construction plane
    adsk::fusion::FeatureHealthStates health = planeOne->healthState();
    if (health == adsk::fusion::FeatureHealthStates::ErrorFeatureHealthState ||
        health == adsk::fusion::FeatureHealthStates::WarningFeatureHealthState)
    {
        std::string msg = planeOne->errorOrWarningMessage();
    }

    // Add construction plane by angle
    Ptr angle = ValueInput::createByString("30.0 deg");
    planeInput->setByAngle(sketchLineOne, angle, prof);
    planes->add(planeInput);

    // Add construction plane by two planes
    planeInput->setByTwoPlanes(prof, planeOne);
    planes->add(planeInput);

    // Add construction plane by tangent
    Ptr extSideFaces = extrude->sideFaces();
    if (!extSideFaces)
        return false;
    Ptr cylinderFace = extSideFaces->item(0);
    planeInput->setByTangent(cylinderFace, angle, rootComp->xZConstructionPlane());
    planes->add(planeInput);

    // Add construction plane by two edges
    planeInput->setByTwoEdges(sketchLineOne, sketchLineTwo);
    planes->add(planeInput);

    // Add construction plane by three points
    planeInput->setByThreePoints(sketchPointOne, sketchPointTwo, sketchPointThree);
    planes->add(planeInput);

    // Add construction plane by tangent at point
    planeInput->setByTangentAtPoint(cylinderFace, sketchPointOne);
    planes->add(planeInput);

    // Add construction plane by distance on path
    distance = ValueInput::createByReal(1.0);
    planeInput->setByDistanceOnPath(sketchLineOne, distance);
    planes->add(planeInput);

    return true;
}
